esqlQuery.esql:
FROM logs-azure.activity.otel-*
// Restrict to Azure Activity Logs
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "Administrative"
// listKeys/action exposes storage account keys — high-privilege, security-sensitive
| WHERE azure.operation.name LIKE "*LISTKEYS*" OR azure.operation.name LIKE "*LISTKEY*"
// Derive caller for grouping (falls back to principal ID for service principals / managed identities)
| EVAL caller = COALESCE(user.id, azure.identity.authorization.evidence.principal.id, "unknown")
// Include both success and failure — attempted access is the signal
| STATS access_count = COUNT(*), result_types = VALUES(azure.result.type) BY caller, azure.identity.authorization.evidence.principal.type, network.peer.address, cloud.resource_id
| SORT access_count DESC
| LIMIT 20
